import { describe, expect, it } from 'vitest';

import {
  encodeWavPcm16,
  handleSpeechRequestBody,
  resolveTtsAudioMode,
  synthesizeSpeechPcm16,
} from '../src/tts-audio';

function ascii(bytes: Uint8Array, start: number, length: number): string {
  return new TextDecoder('ascii').decode(bytes.subarray(start, start + length));
}

describe('Moonshine TTS audio', () => {
  it('resolves audio mode from platform and explicit env overrides', () => {
    expect(resolveTtsAudioMode(undefined, { platform: 'darwin' })).toBe('host');
    expect(
      resolveTtsAudioMode(undefined, {
        platform: 'linux',
        hasAlsaDevice: () => true,
      }),
    ).toBe('alsa');
    expect(
      resolveTtsAudioMode(undefined, {
        platform: 'linux',
        hasAlsaDevice: () => false,
      }),
    ).toBe('file');
    expect(resolveTtsAudioMode('pulse', { platform: 'darwin' })).toBe('pulse');
    expect(resolveTtsAudioMode('host', { platform: 'linux' })).toBe('host');
  });

  it('encodes valid RIFF/WAVE bytes for local speech synthesis', () => {
    const pcm = synthesizeSpeechPcm16('hello moonshine');
    const wav = encodeWavPcm16(pcm);

    expect(ascii(wav, 0, 4)).toBe('RIFF');
    expect(ascii(wav, 8, 4)).toBe('WAVE');
    expect(ascii(wav, 36, 4)).toBe('data');
    expect(wav.byteLength).toBe(44 + pcm.byteLength);
  });

  it('returns audio/wav for /v1/audio/speech-compatible requests', async () => {
    const response = await handleSpeechRequestBody(
      JSON.stringify({ input: 'short local speech', voice: 'moonshine' }),
      {
        env: { MOONSHINE_TTS_AUDIO_MODE: 'host' },
        platform: 'darwin',
      },
    );

    expect(response.status).toBe(200);
    expect(response.headers['Content-Type']).toBe('audio/wav');
    expect(response.headers['X-Moonshine-TTS-Audio-Mode']).toBe('host');
    expect(ascii(response.body, 0, 4)).toBe('RIFF');
  });

  it('rejects missing input without emitting audio', async () => {
    const response = await handleSpeechRequestBody(JSON.stringify({ voice: 'moonshine' }));

    expect(response.status).toBe(400);
    expect(response.headers['Content-Type']).toBe('application/json');
  });
});
